<script setup lang="ts">import{useI18n}from'vue-i18n';defineProps<{name:string;content:string;busy:boolean}>();defineEmits<{'update:name':[string];'update:content':[string];save:[]}>();const{t}=useI18n()</script>
<template><div class="prompt-editor"><label>{{t('prompts.name')}}<input :value="name" :disabled="busy" @input="$emit('update:name',($event.target as HTMLInputElement).value)"></label><label>{{t('prompts.content')}}<textarea :value="content" :disabled="busy" rows="16" @input="$emit('update:content',($event.target as HTMLTextAreaElement).value)"/></label><p>{{content.length}} {{t('prompts.characters')}}</p><button class="primary-button" type="button" :disabled="busy||!name.trim()" @click="$emit('save')">{{t('prompts.save')}}</button></div></template>
